SELECT
    intDiv(block_number, 7200) * 7200 AS block_bucket,
    multiIf(
        target_address = '0x0000000000000000000000000000000000000001', 'ecrecover',
        target_address = '0x0000000000000000000000000000000000000002', 'sha256',
        target_address = '0x0000000000000000000000000000000000000004', 'identity',
        target_address = '0x0000000000000000000000000000000000000005', 'modexp',
        target_address = '0x0000000000000000000000000000000000000006', 'ecAdd',
        target_address = '0x0000000000000000000000000000000000000007', 'ecMul',
        target_address = '0x0000000000000000000000000000000000000008', 'ecPairing',
        target_address = '0x000000000000000000000000000000000000000a', 'point_eval',
        target_address = '0x000000000000000000000000000000000000000b', 'bls12_g1add',
        target_address = '0x000000000000000000000000000000000000000c', 'bls12_g1mul',
        target_address = '0x000000000000000000000000000000000000000d', 'bls12_g1multiexp',
        target_address = '0x000000000000000000000000000000000000000e', 'bls12_g2add',
        target_address = '0x000000000000000000000000000000000000000f', 'bls12_g2mul',
        target_address = '0x0000000000000000000000000000000000000010', 'bls12_g2multiexp',
        target_address = '0x0000000000000000000000000000000000000011', 'bls12_pairing',
        target_address = '0x0000000000000000000000000000000000000012', 'bls12_map_fp_to_g1',
        target_address = '0x0000000000000000000000000000000000000013', 'bls12_map_fp2_to_g2',
        'other'
    ) AS precompile,
    count() AS total_calls,
    sum(gas) AS total_gas
FROM mainnet.int_transaction_call_frame FINAL
WHERE block_number BETWEEN 24120001 AND 24546241
    AND target_address IN (
        '0x0000000000000000000000000000000000000001',
        '0x0000000000000000000000000000000000000002',
        '0x0000000000000000000000000000000000000003',
        '0x0000000000000000000000000000000000000004',
        '0x0000000000000000000000000000000000000005',
        '0x0000000000000000000000000000000000000006',
        '0x0000000000000000000000000000000000000007',
        '0x0000000000000000000000000000000000000008',
        '0x0000000000000000000000000000000000000009',
        '0x000000000000000000000000000000000000000a',
        '0x000000000000000000000000000000000000000b',
        '0x000000000000000000000000000000000000000c',
        '0x000000000000000000000000000000000000000d',
        '0x000000000000000000000000000000000000000e',
        '0x000000000000000000000000000000000000000f',
        '0x0000000000000000000000000000000000000010',
        '0x0000000000000000000000000000000000000011',
        '0x0000000000000000000000000000000000000012',
        '0x0000000000000000000000000000000000000013'
    )
GROUP BY block_bucket, precompile
ORDER BY block_bucket ASC, total_calls DESC
